#include <bits/stdc++.h>
using namespace std;
stack<unsigned long long> s;
int main(){
    int t,n;unsigned long long x;string c;
    cin>>t;
    for(int i=1;i<=t;i++){
        while(!s.empty())s.pop();
        cin>>n;
        for(int j=1;j<=n;j++){
            cin>>c;
            if(c=="push"){
                cin>>x;
                s.push(x);
            }
            else if(c=="pop"){
                if(s.empty())cout<<"Empty"<<endl;
                else s.pop();
            }
            else if(c=="size")cout<<s.size()<<endl;
            else if(c=="query"){
                if(s.empty())cout<<"Anguei!"<<endl;
                else cout<<s.top()<<endl;
            }
        }
    }
    return 0;
}
